+    user: {
+        handle: 'string|null',
+    },
+});
+export const ApiSearchResponseSchema = type({
+    results: [
+        {
+            slug: 'string?',
+            displayName: 'string?',
+            version: 'string|null?',
+            score: 'number',
+        },
+    ],
+});
+export const ApiSkillMetaResponseSchema = type({
+    latestVersion: type({
+        version: 'string',
+    }).optional(),
+    skill: 'unknown|null?',
+});
+export const ApiCliUploadUrlResponseSchema = type({
+    uploadUrl: 'string',
+});
+export const ApiUploadFileResponseSchema = type({
+    storageId: 'string',
+});
+export const CliPublishFileSchema = type({
+    path: 'string',
+    size: 'number',
+    storageId: 'string',
+    sha256: 'string',
+    contentType: 'string?',
+});
+export const CliPublishRequestSchema = type({
+    slug: 'string',
